#include <stdio.h>
#include <signal.h>

typedef struct { int num; const char *name; const char *action; } SigInfo;

/* Test mode: test harness handles validation */

int main(void) {
    {
        printf("%d\n", (int)(SIGHUP));
    }
    {
        printf("%d\n", (int)(SIGINT));
    }
    {
        printf("%d\n", (int)(SIGKILL));
    }
    {
        printf("%d\n", (int)(SIGTERM));
    }
    return 0;
}

